import React from 'react';
import Navigation from './components/Navigation';
import Hero from './components/Hero';
import About from './components/About';
import Skills from './components/Skills';
import Projects from './components/Projects';
import Contact from './components/Contact';
import silhouette1 from './assets/silhouette1.png';
import silhouette2 from './assets/silhouette2.png';
import silhouette3 from './assets/silhouette3.png';
import './styles/App.css';

function App() {
  return (
    <div className="App">
      <div className="tech-grid"></div>
      <div className="aircraft-backgrounds">
        {/* #region agent log */}
        <img src={silhouette1} alt="" className="bg-aircraft bg-aircraft-1" onLoad={(e) => {const img=e.target;fetch('http://127.0.0.1:7242/ingest/b49a5b9a-2f04-451a-86d8-a4294227c5a1',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'App.jsx:18',message:'Silhouette1 loaded with dimensions',data:{image:'silhouette1',width:img.naturalWidth,height:img.naturalHeight,computedOpacity:window.getComputedStyle(img).opacity,computedDisplay:window.getComputedStyle(img).display,computedVisibility:window.getComputedStyle(img).visibility},timestamp:Date.now(),sessionId:'debug-session',runId:'run2',hypothesisId:'B'})}).catch(()=>{})}} onError={(e) => fetch('http://127.0.0.1:7242/ingest/b49a5b9a-2f04-451a-86d8-a4294227c5a1',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'App.jsx:18',message:'Silhouette1 failed',data:{error:e.type},timestamp:Date.now(),sessionId:'debug-session',runId:'run2',hypothesisId:'B'})}).catch(()=>{})} />
        {/* #endregion */}
        {/* #region agent log */}
        <img src={silhouette2} alt="" className="bg-aircraft bg-aircraft-2" onLoad={(e) => {const img=e.target;fetch('http://127.0.0.1:7242/ingest/b49a5b9a-2f04-451a-86d8-a4294227c5a1',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'App.jsx:19',message:'Silhouette2 loaded with dimensions',data:{image:'silhouette2',width:img.naturalWidth,height:img.naturalHeight,computedOpacity:window.getComputedStyle(img).opacity,computedDisplay:window.getComputedStyle(img).display,computedVisibility:window.getComputedStyle(img).visibility},timestamp:Date.now(),sessionId:'debug-session',runId:'run2',hypothesisId:'B'})}).catch(()=>{})}} onError={(e) => fetch('http://127.0.0.1:7242/ingest/b49a5b9a-2f04-451a-86d8-a4294227c5a1',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'App.jsx:19',message:'Silhouette2 failed',data:{error:e.type},timestamp:Date.now(),sessionId:'debug-session',runId:'run2',hypothesisId:'B'})}).catch(()=>{})} />
        {/* #endregion */}
        {/* #region agent log */}
        <img src={silhouette3} alt="" className="bg-aircraft bg-aircraft-3" onLoad={(e) => {const img=e.target;fetch('http://127.0.0.1:7242/ingest/b49a5b9a-2f04-451a-86d8-a4294227c5a1',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'App.jsx:20',message:'Silhouette3 loaded with dimensions',data:{image:'silhouette3',width:img.naturalWidth,height:img.naturalHeight,computedOpacity:window.getComputedStyle(img).opacity,computedDisplay:window.getComputedStyle(img).display,computedVisibility:window.getComputedStyle(img).visibility},timestamp:Date.now(),sessionId:'debug-session',runId:'run2',hypothesisId:'B'})}).catch(()=>{})}} onError={(e) => fetch('http://127.0.0.1:7242/ingest/b49a5b9a-2f04-451a-86d8-a4294227c5a1',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'App.jsx:20',message:'Silhouette3 failed',data:{error:e.type},timestamp:Date.now(),sessionId:'debug-session',runId:'run2',hypothesisId:'B'})}).catch(()=>{})} />
        {/* #endregion */}
        {/* #region agent log */}
        <img src={silhouette2} alt="" className="bg-aircraft bg-aircraft-4" onLoad={(e) => {const img=e.target;fetch('http://127.0.0.1:7242/ingest/b49a5b9a-2f04-451a-86d8-a4294227c5a1',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'App.jsx:21',message:'Silhouette4 loaded with dimensions',data:{image:'silhouette2',width:img.naturalWidth,height:img.naturalHeight,computedOpacity:window.getComputedStyle(img).opacity,computedDisplay:window.getComputedStyle(img).display,computedVisibility:window.getComputedStyle(img).visibility},timestamp:Date.now(),sessionId:'debug-session',runId:'run2',hypothesisId:'B'})}).catch(()=>{})}} onError={(e) => fetch('http://127.0.0.1:7242/ingest/b49a5b9a-2f04-451a-86d8-a4294227c5a1',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'App.jsx:21',message:'Silhouette4 failed',data:{error:e.type},timestamp:Date.now(),sessionId:'debug-session',runId:'run2',hypothesisId:'B'})}).catch(()=>{})} />
        {/* #endregion */}
      </div>
      <Navigation />
      <Hero />
      <About />
      <Skills />
      <Projects />
      <Contact />
    </div>
  );
}

export default App;
